'use client';

import { useState } from 'react';
import Link from 'next/link';
import { usePathname, useRouter } from 'next/navigation';
import { motion } from 'framer-motion';
import { Hash, User, PenSquare } from 'lucide-react';
import { useAuth } from '@/contexts/AuthContext';
import UpgradeModal from '@/components/subscription/UpgradeModal';

export default function MobileNav() {
  const pathname = usePathname();
  const router = useRouter();
  const { currentUser } = useAuth();
  const [showUpgrade, setShowUpgrade] = useState(false);

  const isReader = currentUser?.role === 'reader';
  const isWriter = currentUser?.role === 'editor' || currentUser?.role === 'admin';

  const handleWriteClick = () => {
    if (!currentUser) { router.push('/login'); return; }
    if (isReader) { setShowUpgrade(true); return; }
    router.push('/article/create');
  };

  const items = [
    { href: '/topics', icon: Hash, label: 'Chủ đề' },
    { href: '/profile', icon: User, label: 'Cá nhân' },
  ];

  return (
    <>
      <nav
        className="fixed bottom-0 left-0 right-0 border-t lg:hidden z-50"
        style={{ background: 'var(--bg-glass)', backdropFilter: 'var(--glass-blur-heavy)', WebkitBackdropFilter: 'var(--glass-blur-heavy)', borderColor: 'var(--border-glass)' }}
      >
        <div className="flex items-center justify-around py-2">
          {items.map((item) => {
            const isActive = item.href === '/' ? pathname === '/' : pathname.startsWith(item.href);
            const Icon = item.icon;
            return (
              <Link key={item.href} href={item.href} className="flex flex-col items-center gap-0.5 px-4 py-1.5 rounded-lg">
                <Icon className="w-6 h-6" style={{ color: isActive ? '#F97316' : 'var(--text-secondary)' }} strokeWidth={isActive ? 2.5 : 2} />
                <span className="text-[10px]" style={{ color: isActive ? '#F97316' : 'var(--text-secondary)' }}>{item.label}</span>
              </Link>
            );
          })}

          {/* Viết bài */}
          {currentUser && (
            <motion.button
              whileTap={{ scale: 0.9 }}
              onClick={handleWriteClick}
              className="flex flex-col items-center gap-0.5 px-4 py-1.5 rounded-lg relative"
            >
              <div className="relative">
                <PenSquare
                  className="w-6 h-6"
                  style={{ color: isReader ? 'var(--text-secondary)' : pathname === '/article/create' ? '#F97316' : 'var(--text-secondary)' }}
                  strokeWidth={pathname === '/article/create' ? 2.5 : 2}
                />
                {/* Lock dot for reader */}
                {isReader && (
                  <span className="absolute -top-1 -right-1 w-3 h-3 rounded-full text-white flex items-center justify-center text-[7px] font-bold" style={{ background: '#F97316' }}>
                    🔒
                  </span>
                )}
              </div>
              <span className="text-[10px]" style={{ color: isReader ? 'var(--text-secondary)' : pathname === '/article/create' ? '#F97316' : 'var(--text-secondary)' }}>
                Viết bài
              </span>
            </motion.button>
          )}
        </div>
      </nav>

      {showUpgrade && <UpgradeModal onClose={() => setShowUpgrade(false)} />}
    </>
  );
}
